typedef enum { NODE_INT, NODE_BIN_OP } NodeKind;
typedef struct Node Node;

struct Node {
    NodeKind kind;
    union {
        int value;  // NODE_INT
        struct { Node *left; char op; Node *right; }; // NODE_BIN_OP (anonymous)
    };
};

int eval(const Node *n) {
    if (n->kind == NODE_INT) return n->value;
    int l = eval(n->left), r = eval(n->right);
    switch (n->op) {
        case '+': return l + r;
        case '*': return l * r;
        default: return 0;
    }
}

int main() {
    Node a = {NODE_INT, .value = 3};
    Node b = {NODE_INT, .value = 4};
    Node expr = {NODE_BIN_OP, .left = &a, .op = '+', .right = &b};
    printf("3 + 4 = %d\n", eval(&expr));
    return 0;
}

