static inline int fast_log2(uint32_t n) {
    int log = 0;
    if (n & 0xFFFF0000) { n >>= 16; log += 16; }
    if (n & 0xFF00)     { n >>= 8;  log += 8;  }
    if (n & 0xF0)       { n >>= 4;  log += 4;  }
    if (n & 0xC)        { n >>= 2;  log += 2;  }
    if (n & 0x2)        {           log += 1;  }
    return log;
}

