void quicksort_iterative(int *arr, int n) {
    Frame *stack = malloc(n * sizeof(Frame));
    int top = 0;
    stack[top++] = (Frame){0, n-1};
    while (top > 0) {
        Frame f = stack[--top];
        if (f.low >= f.high) continue;
        int pivot = arr[f.high], i = f.low;
        for (int j = f.low; j < f.high; j++)
            if (arr[j] < pivot) { int t=arr[i]; arr[i]=arr[j]; arr[j]=t; i++; }
        int t=arr[i]; arr[i]=arr[f.high]; arr[f.high]=t;
        stack[top++] = (Frame){f.low, i-1};
        stack[top++] = (Frame){i+1, f.high};
    }
    free(stack);
}

