#define SIZE 1024

typedef struct {
    int buffer[SIZE];
    _Atomic size_t head;
    _Atomic size_t tail;
} SPSCQueue;

int spsc_push(SPSCQueue *q, int val) {
    size_t tail = atomic_load_explicit(&q->tail, memory_order_relaxed);
    size_t next = (tail + 1) % SIZE;
    if (next == atomic_load_explicit(&q->head, memory_order_acquire))
        return -1; // full
    q->buffer[tail] = val;
    atomic_store_explicit(&q->tail, next, memory_order_release);
    return 0;
}

int spsc_pop(SPSCQueue *q, int *val) {
    size_t head = atomic_load_explicit(&q->head, memory_order_relaxed);
    if (head == atomic_load_explicit(&q->tail, memory_order_acquire))
        return -1; // empty
    *val = q->buffer[head];
    atomic_store_explicit(&q->head, (head+1)%SIZE, memory_order_release);
    return 0;
}

